const jobs = $input.all().map(i => i.json);
if (jobs.length === 0) return [{ json: { skip: true } }];
const aJobs = jobs.filter(j => j.tier === 'A');
const bJobs = jobs.filter(j => j.tier === 'B');
const date = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
let html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html += '<h2 style="color:#1a1a1a;">Job Digest - ' + date + '</h2>';
html += '<p style="color:#555;">Found <strong>' + aJobs.length + ' strong matches</strong> and <strong>' + bJobs.length + ' worth reviewing</strong>.</p>';
if (aJobs.length > 0) {
  html += '<h3 style="color:#16a34a;border-bottom:2px solid #16a34a;padding-bottom:4px;">Strong Matches (Tier A)</h3>';
  for (const j of aJobs) {
    html += '<div style="margin-bottom:16px;padding:12px;border-left:4px solid #22c55e;background:#f0fdf4;border-radius:4px;">';
    html += '<strong><a href="' + j.url + '" style="color:#1a1a1a;text-decoration:none;">' + j.title + '</a></strong><br/>';
    html += '<span style="color:#555;">' + j.company + ' - ' + j.location + '</span><br/>';
    if (j.salary_raw) html += '<span style="color:#059669;">' + j.salary_raw + '</span><br/>';
    html += '<small style="color:#888;">Score: ' + j.composite_score + '/100 | ' + j.job_type + '</small>';
    if (j.reasoning) html += '<br/><small style="color:#666;font-style:italic;">' + j.reasoning + '</small>';
    html += '</div>';
  }
}
if (bJobs.length > 0) {
  html += '<h3 style="color:#2563eb;border-bottom:2px solid #2563eb;padding-bottom:4px;">Worth Reviewing (Tier B)</h3>';
  for (const j of bJobs) {
    html += '<div style="margin-bottom:12px;padding:8px;border-left:4px solid #3b82f6;background:#eff6ff;border-radius:4px;">';
    html += '<strong><a href="' + j.url + '" style="color:#1a1a1a;text-decoration:none;">' + j.title + '</a></strong><br/>';
    html += '<span style="color:#555;">' + j.company + ' - ' + j.location + '</span><br/>';
    if (j.salary_raw) html += '<span style="color:#2563eb;">' + j.salary_raw + '</span><br/>';
    html += '<small style="color:#888;">Score: ' + j.composite_score + '/100</small>';
    html += '</div>';
  }
}
html += '<hr style="border:none;border-top:1px solid #e5e7eb;margin:24px 0;"/>';
html += '<p style="color:#888;font-size:12px;">Selvi Job Discovery System</p></div>';
const subject = aJobs.length + ' strong + ' + bJobs.length + ' more jobs - ' + new Date().toLocaleDateString('en-GB');
return [{ json: { subject, html, skip: false, total: jobs.length } }];

